                $map[$id] = [pscustomobject]@{
                    Suite     = $t.Suite
                    Name      = $t.Name
                    PassCount = 0
                    FailCount = 0
                    Messages  = New-Object System.Collections.Generic.List[string]
                }
            }
            $entry = $map[$id]
            switch ($t.Outcome) {
                'passed' { $entry.PassCount++ }
                'failed' {
                    $entry.FailCount++
